// 行番号から現在の選択言語のテキストを返す関数
function 文字列取得(行番号){
  const 言語 = localStorage.getItem("選択言語") || "ja";
  if(辞書[行番号]){
    return 辞書[行番号][言語] || 辞書[行番号]["ja"];
  }
  return "？" + 行番号;
}
